// // This module selects between two 32-bit inputs based on the 'select' signal. When 'select' is 1, the output will be assigned the value of 'data1'; when 'select' is 0, the output will take the value of 'data2'.
module top_module(
    input [31:0] data1,
    input [31:0] data2,
    input select,
    output [31:0] out
    );assign out = select == 0 ? data1:data2;
endmodule
